import React from "react";

export default function DemoLicenseModal({ open, onClose }) {
  if (!open) return null;

  return (
    <div
      onClick={onClose}
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.65)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 16,
        zIndex: 50,
      }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          width: "min(980px, 100%)",
          background: "#121212",
          border: "1px solid #333",
          borderRadius: 16,
          padding: 20,
          color: "white",
        }}
      >
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <h3 style={{ margin: 0, fontSize: 26 }}>Demo Screening License</h3>
          <button onClick={onClose} style={{ background: "transparent", border: 0, color: "white", fontSize: 22, cursor: "pointer" }}>
            ✕
          </button>
        </div>

        <p style={{ opacity: 0.8 }}>
          This demo film can be screened only once. After playback, access expires automatically.
        </p>

        <button
          style={{
            marginTop: 16,
            padding: "14px 18px",
            borderRadius: 10,
            border: 0,
            background: "#f08a1a",
            color: "white",
            fontWeight: 800,
            cursor: "pointer",
          }}
        >
          ▶ Start Demo Download
        </button>
      </div>
    </div>
  );
}
